const IMathAdapter = require('../../../core/domain/interfaces/IMathAdapter');
module.exports = class AdvancedBigIntProcessor extends IMathAdapter {
  constructor() { super(); this.N = BigInt(''); }
  async factorize(p, q) {
    const bp = BigInt(p); const bq = BigInt(q);
    if(bp === 1n || bq === 1n) return false;
    return (bp * bq === this.N);
  }
};
